import requests
from bs4 import BeautifulSoup
from utils.logger import setup_logger

logger = setup_logger("ContentAnalyzer", "content_analysis.log")


def analyze_html_content(url: str, html_content: str = None) -> float:
    """
    Analyzes HTML content for phishing indicators.
    Returns a content risk score between 0.0 (Safe) and 1.0 (High Risk).
    """
    if not html_content:
        return 0.0

    risk_score = 0.0

    try:
        soup = BeautifulSoup(html_content, 'html.parser')

        # ── 1. Password field + external form action (phishing combo) ──────────
        password_inputs = soup.find_all('input', {'type': 'password'})
        if password_inputs:
            forms = soup.find_all('form')
            external_action = False
            for form in forms:
                action = form.get('action', '')
                if action and action.startswith('http') and not _same_domain(url, action):
                    external_action = True
                    break
            if external_action:
                risk_score += 0.55
                logger.info(f"Password field + external form action on {url}")
            else:
                risk_score += 0.12

        # ── 2. Login form action keywords ─────────────────────────────────────
        for form in soup.find_all('form'):
            action = form.get('action', '').lower()
            if any(kw in action for kw in ('phish', 'steal', 'harvest')):
                risk_score += 0.40

        # ── 3. Excessive hidden elements (obfuscation) ────────────────────────
        hidden = soup.find_all(style=lambda v: v and 'display:none' in v.replace(' ', ''))
        if len(hidden) > 10:
            risk_score += 0.20
        elif len(hidden) > 5:
            risk_score += 0.08

        # ── 4. Suspicious external iFrames ────────────────────────────────────
        suspicious_iframes = 0
        for iframe in soup.find_all('iframe'):
            src = iframe.get('src', '')
            if src and src.startswith('http') and not _same_domain(url, src):
                suspicious_iframes += 1
        if suspicious_iframes >= 3:
            risk_score += 0.30
        elif suspicious_iframes >= 1:
            risk_score += 0.08

        # ── 5. Suspicious page title ──────────────────────────────────────────
        title = ''
        if soup.title and soup.title.string:
            title = soup.title.string.lower()
        if any(kw in title for kw in ('verify your account', 'security check', 'your wallet')):
            risk_score += 0.25

        return min(1.0, risk_score)

    except Exception as e:
        logger.error(f"Content analysis error for {url}: {e}")
        return 0.0


def _same_domain(base_url: str, target_url: str) -> bool:
    try:
        import tldextract
        b = tldextract.extract(base_url)
        t = tldextract.extract(target_url)
        return f"{b.domain}.{b.suffix}" == f"{t.domain}.{t.suffix}"
    except Exception:
        return False

document.addEventListener('DOMContentLoaded', () => {
    // Fetch the exact details from Chrome Local Storage (set by background.js)
    chrome.storage.local.get(['lastResult'], function(data) {
        const result = data.lastResult || {};

        // 1. Set URL (Fallback to unknown if missing)
        const finalUrl = result.url || 'Unknown Target URL';
        document.getElementById('url-text').textContent = finalUrl;

        // 2. Set Score
        // Ensure we grab the score accurately regardless of the field name
        let scoreVal = 0.85; // Default high risk score
        if (result.score !== undefined) scoreVal = parseFloat(result.score);
        else if (result.risk_score !== undefined) scoreVal = parseFloat(result.risk_score);
        else if (result.final_score !== undefined) scoreVal = parseFloat(result.final_score);

        document.getElementById('score-text').textContent = scoreVal.toFixed(2);

        // Animate progress bar slightly after load for effect
        setTimeout(() => {
            const percentage = Math.min(100, Math.max(0, scoreVal * 100));
            document.getElementById('score-bar').style.width = percentage + '%';
        }, 100);

        // 3. Set Category Tag
        const category = result.category || 'MALWARE';
        if (category === 'PHISHING') {
            document.getElementById('tag-phishing').classList.add('active');
        } else if (category === 'PIRACY') {
            document.getElementById('tag-piracy').classList.add('active');
        } else if (category === 'MALWARE') {
            document.getElementById('tag-malware').classList.add('active');
        } else {
            document.getElementById('tag-suspicious').classList.add('active');
        }

        // 4. Set Reasons List
        const reasonsText = document.getElementById('reasons-text');
        const finalReasons = (result.reasons && result.reasons.length > 0) 
                             ? result.reasons 
                             : ["Unauthorized or malicious indicators found."];
        reasonsText.textContent = finalReasons.join(" | ");
    });

    // 5. Button Actions
    document.getElementById('btn-back').addEventListener('click', () => {
         // Try to go back in history. 
         if (window.history.length > 2) {
             window.history.back();
         } else {
             // If no history exists, go to Google as fallback, or close the tab
             chrome.tabs.getCurrent(function(tab) {
                 if (tab) {
                     chrome.tabs.remove(tab.id);
                 } else {
                     window.location.href = "https://www.google.com";
                 }
             });
         }
    });

    document.getElementById('btn-new').addEventListener('click', () => {
        // Attempt to create a new tab. window.location.href = "chrome://newtab/" is blocked by CSP
        chrome.tabs.create({});
    });
});

// AI Smart Firewall — Background Service Worker (MV3)
const API_URL = "http://127.0.0.1:5000/check-url";
const API_TIMEOUT_MS = 6000; // Increased to 6s to account for slow networks + 3.5s backend timeout

// Whitelist patterns that should NEVER be intercepted
const IGNORE_PATTERNS = [
    "chrome://",
    "chrome-extension://",
    "edge://",
    "http://127.0.0.1",
    "http://localhost",
    "https://localhost",
    "about:",
    "file://",
    "view-source:",
    "https://www.google.com/search" // Don't intercept search result pages to reduce lag
];

function shouldIgnore(url) {
    if (!url) return true;
    return IGNORE_PATTERNS.some(pattern => url.startsWith(pattern));
}

// Utility: fetch with timeout to prevent hanging the browser
async function fetchWithTimeout(url, options, ms) {
    const controller = new AbortController();
    const id = setTimeout(() => controller.abort(), ms);
    try {
        return await fetch(url, { ...options, signal: controller.signal });
    } finally {
        clearTimeout(id);
    }
}

chrome.webNavigation.onBeforeNavigate.addListener(async (details) => {
    // Only intercept top-level frame navigations
    if (details.frameId !== 0) return;

    const url = details.url;

    // 1. Filtering: Ignore internal, local, and search engine query pages (for performance)
    if (shouldIgnore(url)) {
        return;
    }

    // Ignore our own blocked page
    if (url.includes(chrome.runtime.id)) return;

    console.log(`[AI Firewall] Checking: ${url}`);

    try {
        const response = await fetchWithTimeout(API_URL, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ url })
        }, API_TIMEOUT_MS);

        if (!response.ok) {
            console.warn(`[AI Firewall] API error ${response.status}. Allowing.`);
            return;
        }

        const result = await response.json();

        console.log(`[AI Firewall] Result: ${result.decision} (Score: ${result.score || result.risk_score || 0})`);

        // Update badge
        let color = "#00ff00"; // Safe
        let text = "";

        if (result.decision === "BLOCK") {
            color = "#ff0000";
            text = "!";
        } else if (result.decision === "WARN") {
            color = "#ffcc00";
            text = "?";
        }

        chrome.action.setBadgeBackgroundColor({ color, tabId: details.tabId });
        chrome.action.setBadgeText({ text, tabId: details.tabId });

        // Store result for popup and blocked.html using local storage (more reliable than session)
        chrome.storage.local.set({ 
            lastResult: { url, ...result, tabId: details.tabId, timestamp: Date.now() } 
        }, () => {
            // 2. BLOCK REDIRECTION (Wait for storage to save first)
            if (result.decision === "BLOCK") {
                const blockedPageUrl = chrome.runtime.getURL("blocked.html");
                console.log(`[AI Firewall] Blocking threat: ${url}`);
                chrome.tabs.update(details.tabId, { url: blockedPageUrl });
            }
        });

    } catch (err) {
        // Log detail but allow navigation to prevent breaking the web on network lag
        console.warn(`[AI Firewall] Pass-through (Timeout/Unreachable): ${err.message}`);
    }
});

// Clear badge on new loads
chrome.tabs.onUpdated.addListener((tabId, changeInfo) => {
    if (changeInfo.status === 'loading') {
        chrome.action.setBadgeText({ text: "", tabId });
    }
});

// AI Smart Firewall - Popup Script
// Reads the last firewall decision from storage and displays it in the popup.

function getDecisionIcon(decision) {
    switch (decision) {
        case "BLOCK": return "⛔";
        case "WARN": return "⚠️";
        case "ALLOW": return "✅";
        default: return "🔍";
    }
}

function getDecisionText(decision) {
    switch (decision) {
        case "BLOCK": return "BLOCKED - Threat Detected";
        case "WARN": return "WARNING - Suspicious";
        case "ALLOW": return "SAFE";
        default: return "Unknown";
    }
}

document.addEventListener("DOMContentLoaded", () => {
    const area = document.getElementById("result-area");

    chrome.storage.local.get("lastResult", (data) => {
        const r = data.lastResult;
        if (!r) {
            area.innerHTML = `<p class="no-data">Browse a website to see the firewall analysis.</p>`;
            return;
        }

        const score = parseFloat(r.score || 0);
        const barWidth = Math.round(score * 100);

        area.innerHTML = `
            <div class="status-card">
                <div class="status-label">Firewall Decision</div>
                <div class="decision ${r.decision}">
                    ${getDecisionIcon(r.decision)} ${getDecisionText(r.decision)}
                </div>
                <div class="score-bar-bg">
                    <div class="score-bar ${r.decision}" style="width: ${barWidth}%"></div>
                </div>
                <div style="margin-top: 6px; font-size: 11px; color: #8b949e;">
                    Risk Score: <strong style="color: #e6edf3;">${score.toFixed(2)}</strong>
                </div>
            </div>
            <div class="status-label" style="margin-bottom: 6px;">Analyzed URL</div>
            <div class="url-box">${r.url}</div>
        `;
    });
});

from flask import Flask, request, jsonify
from flask_cors import CORS
import sys
import os

# Add project root to path
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from src.risk_engine import analyze_traffic_risk
from utils.logger import setup_logger

app = Flask(__name__)
CORS(app)  # Allow extension to call this API
logger = setup_logger("APIServer", "api_server.log")


@app.route("/", methods=["GET"])
def home():
    return jsonify({
        "message": "🛡️ AI Smart Firewall API is running!",
        "endpoints": {
            "health": "GET /health",
            "check_url": "POST /check-url"
        }
    })


@app.route("/check-url", methods=["POST"])
def analyze_url():
    """
    Main API endpoint for the browser extension.
    Accepts: {"url": "https://example.com"}
    Returns: {"decision": "ALLOW|WARN|BLOCK", "score": 0.45, "category": "...", "reasons": [...]}
    """
    data = request.get_json()
    if not data or "url" not in data:
        return jsonify({"error": "No URL provided"}), 400

    url = data["url"]

    try:
        # Run the full parallel multi-layer analysis
        result = analyze_traffic_risk(url)

        response = {
            "decision": result.decision,
            "score": round(result.final_score, 4),
            "category": result.category,
            "reasons": result.reasons
        }

        logger.info(f"API result for {url}: {result.decision} (score {result.final_score:.4f})")
        return jsonify(response)

    except Exception as e:
        logger.error(f"Error analyzing {url}: {str(e)}")
        return jsonify({
            "decision": "ALLOW",
            "score": 0.0,
            "category": "ERROR",
            "reasons": ["Analysis failed due to internal error"]
        }), 500


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "healthy"}), 200


if __name__ == "__main__":
    # Runs on internal port 5000 (Streamlit takes the public Render PORT)
    app.run(host="0.0.0.0", port=5000, debug=False)
